import {
    Box,
    SimpleGrid,
    Heading,
    Text,
    VStack,
    HStack,
    Icon,
    usePrefersReducedMotion,
    Wrap,
    WrapItem,
    Badge,
    useColorModeValue
} from '@chakra-ui/react';
import { motion } from 'framer-motion';
import { FiLayout, FiZap, FiEye, FiShield } from 'react-icons/fi';

const MotionBox = motion(Box);

const features = [
    {
        title: 'Component Architecture',
        description: 'Building scalable, reusable, and maintainable component libraries.',
        icon: FiLayout,
    },
    {
        title: 'Performance Optimization',
        description: 'Fine-tuning React lifecycles and bundle sizes for speed.',
        icon: FiZap,
    },
    {
        title: 'Accessibility-First UI',
        description: 'Ensuring all interfaces are keyboard navigable and screen-reader friendly.',
        icon: FiEye,
    },
    {
        title: 'Testing & Maintainability',
        description: 'Comprehensive unit and integration testing workflows.',
        icon: FiShield,
    },
];

const AboutSection = () => {
    const prefersReducedMotion = usePrefersReducedMotion();

    const bg = useColorModeValue('white', 'gray.900');
    const titleColor = useColorModeValue('gray.900', 'white');
    const subtitleColor = useColorModeValue('brand.500', 'brand.300');
    const textColor = useColorModeValue('gray.700', 'gray.300');
    const headingColor = useColorModeValue('gray.800', 'gray.100');

    const featureBg = useColorModeValue('bg', 'gray.800');
    const featureBorder = useColorModeValue('gray.200', 'whiteAlpha.200');
    const featureHoverBorder = useColorModeValue('brand.200', 'brand.500');
    const featureIconBg = useColorModeValue('white', 'gray.700');
    const featureTitleColor = useColorModeValue('gray.800', 'white');
    const featureDescColor = useColorModeValue('gray.600', 'gray.400');

    return (
        <Box id="about" py={20} bg={bg}>
            <Box maxW="1280px" mx="auto" px={{ base: 6, md: 8 }}>
                <MotionBox
                    initial={{ opacity: 0, y: prefersReducedMotion ? 0 : 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: '-100px' }}
                    transition={{ duration: 0.5, ease: [0.4, 0, 0.2, 1] }}
                >
                    <Heading as="h2" size="2xl" mb={12} textAlign="center" color={titleColor}>
                        Behind the Code
                    </Heading>
                </MotionBox>

                <SimpleGrid columns={{ base: 1, lg: 2 }} spacing={12} alignItems="center">
                    <MotionBox
                        initial={{ opacity: 0, x: prefersReducedMotion ? 0 : -30 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true, margin: '-100px' }}
                        transition={{ duration: 0.6, ease: [0.4, 0, 0.2, 1] }}
                    >
                        <VStack align="flex-start" spacing={6}>
                            <Text fontSize="xl" fontWeight="semibold" color={subtitleColor}>
                                What I bring to the table
                            </Text>
                            <Text fontSize="lg" color={textColor} lineHeight="tall">
                                As a motivated Junior Developer, my core focus is bridging the gap between elegant design and clean technical architecture. I believe that performance and accessibility are not afterthoughts, but foundational pillars of good UI engineering.
                            </Text>
                            <Text fontSize="lg" color={textColor} lineHeight="tall">
                                I have spent my recent time honing my skills in modern tools like React and JavaScript to deliver products that look great and feel incredibly responsive.
                            </Text>

                            <Box mt={4}>
                                <Text fontWeight="bold" mb={3} color={headingColor}>Core Technologies</Text>
                                <Wrap spacing={2}>
                                    {['HTML', 'CSS', 'Bootstrap', 'JavaScript', 'React', 'Python', 'Java', 'SQL', 'Git', 'GitHub', 'CLI'].map((tech) => (
                                        <WrapItem key={tech}>
                                            <Badge colorScheme="blue" variant="subtle" px={3} py={1} borderRadius="md" transition="all 0.2s" _hover={{ transform: 'scale(1.05)', bg: useColorModeValue('blue.200', 'blue.700') }}>
                                                {tech}
                                            </Badge>
                                        </WrapItem>
                                    ))}
                                </Wrap>
                            </Box>
                        </VStack>
                    </MotionBox>

                    <MotionBox
                        initial={{ opacity: 0, x: prefersReducedMotion ? 0 : 30 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true, margin: '-100px' }}
                        transition={{ duration: 0.6, ease: [0.4, 0, 0.2, 1] }}
                    >
                        <VStack spacing={6} align="stretch">
                            {features.map((feature, index) => (
                                <Box
                                    key={index}
                                    p={5}
                                    bg={featureBg}
                                    borderRadius="xl"
                                    border="1px solid"
                                    borderColor={featureBorder}
                                    transition="all 0.3s cubic-bezier(0.4, 0, 0.2, 1)"
                                    _hover={{ boxShadow: useColorModeValue('md', 'dark-lg'), transform: 'translateX(4px)', borderColor: featureHoverBorder }}
                                >
                                    <HStack spacing={4} align="flex-start">
                                        <Box p={3} bg={featureIconBg} borderRadius="lg" color={subtitleColor} boxShadow="sm">
                                            <Icon as={feature.icon} boxSize={6} />
                                        </Box>
                                        <VStack align="flex-start" spacing={1}>
                                            <Text fontWeight="bold" fontSize="lg" color={featureTitleColor}>
                                                {feature.title}
                                            </Text>
                                            <Text color={featureDescColor}>
                                                {feature.description}
                                            </Text>
                                        </VStack>
                                    </HStack>
                                </Box>
                            ))}
                        </VStack>
                    </MotionBox>
                </SimpleGrid>
            </Box>
        </Box>
    );
};

export default AboutSection;

import { Box, Flex, Heading, Text, VStack, HStack, Icon, usePrefersReducedMotion, useColorModeValue, keyframes } from '@chakra-ui/react';
import { motion } from 'framer-motion';
import { FiAward, FiExternalLink } from 'react-icons/fi';
import { certificationsList } from '../data/certifications';

const MotionBox = motion(Box);

const scrollAnimation = keyframes`
  from { transform: translateX(0); }
  to { transform: translateX(calc(-100% - 32px)); }
`;

// Repeat the list to ensure it's wide enough for larger screens
const baseRepeat = [...certificationsList, ...certificationsList, ...certificationsList];

const CertificationsSection = () => {
    const prefersReducedMotion = usePrefersReducedMotion();

    const bg = useColorModeValue('white', 'gray.900');
    const titleColor = useColorModeValue('gray.900', 'white');
    const subtitleColor = useColorModeValue('muted', 'gray.400');

    const cardBg = useColorModeValue('white', 'gray.800');
    const cardBorder = useColorModeValue('gray.200', 'whiteAlpha.200');
    const hoverBorderColor = useColorModeValue('brand.200', 'brand.500');

    const cardTitle = useColorModeValue('gray.800', 'white');
    const cardIssuer = useColorModeValue('brand.600', 'brand.300');
    const cardDesc = useColorModeValue('gray.600', 'gray.400');
    const dateBg = useColorModeValue('gray.100', 'whiteAlpha.200');
    const dateColor = useColorModeValue('gray.700', 'whiteAlpha.900');

    return (
        <Box id="certifications" py={20} bg={bg} overflow="hidden">
            <Box maxW="1280px" mx="auto" px={{ base: 6, md: 8 }} mb={16}>
                <MotionBox
                    initial={{ opacity: 0, y: prefersReducedMotion ? 0 : 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: '-100px' }}
                    transition={{ duration: 0.5, ease: [0.4, 0, 0.2, 1] }}
                >
                    <Heading as="h2" size="2xl" mb={4} textAlign="center" color={titleColor}>
                        Certifications Showcase
                    </Heading>
                    <Text fontSize="lg" color={subtitleColor} textAlign="center" maxW="2xl" mx="auto">
                        A collection of my professional achievements and proven technical capabilities.
                    </Text>
                </MotionBox>
            </Box>

            {/* Scrolling Marquee Container */}
            <Box 
                position="relative" 
                w="full" 
                py={4} 
                sx={{ 
                    _hover: { '.marquee-content': { animationPlayState: 'paused' } },
                    // Fade masks for the edges
                    maskImage: 'linear-gradient(to right, transparent, black 10%, black 90%, transparent)',
                    WebkitMaskImage: 'linear-gradient(to right, transparent, black 10%, black 90%, transparent)'
                }}
            >
                <Flex gap="32px" w="max-content">
                    {/* First Scrolling Block */}
                    <Flex 
                        gap="32px" 
                        className="marquee-content" 
                        animation={prefersReducedMotion ? 'none' : `${scrollAnimation} 40s linear infinite`}
                    >
                        {baseRepeat.map((cert, index) => (
                            <Box
                                key={`first-${cert.id}-${index}`}
                                w={{ base: "300px", md: "400px" }}
                                flexShrink={0}
                                bg={cardBg}
                                p={8}
                                borderRadius="2xl"
                                boxShadow={useColorModeValue('md', 'dark-lg')}
                                border="1px solid"
                                borderColor={cardBorder}
                                transition="all 0.3s cubic-bezier(0.4, 0, 0.2, 1)"
                                _hover={{ transform: 'translateY(-6px)', boxShadow: useColorModeValue('xl', 'dark-lg'), borderColor: hoverBorderColor }}
                                position="relative"
                                display="flex"
                                flexDirection="column"
                            >
                                <Icon as={FiAward} boxSize={10} color={cardIssuer} mb={6} opacity="0.8" />

                                <HStack justify="space-between" align="start" mb={4}>
                                    <VStack align="start" spacing={1}>
                                        <Heading as="h3" size="md" color={cardTitle} lineHeight="tall">
                                            {cert.title}
                                        </Heading>
                                        <Text fontSize="sm" fontWeight="bold" color={cardIssuer} textTransform="uppercase" letterSpacing="wide">
                                            {cert.issuer}
                                        </Text>
                                    </VStack>
                                </HStack>

                                <Text fontSize="md" color={cardDesc} mb={6} flex="1">
                                    {cert.description}
                                </Text>

                                <HStack justify="space-between" mt="auto" pt={4}>
                                    <Text fontSize="sm" fontWeight="semibold" bg={dateBg} color={dateColor} px={3} py={1} borderRadius="md">
                                        Received: {cert.date}
                                    </Text>
                                    {cert.link && cert.link !== "#" && (
                                        <Box as="a" href={cert.link} target="_blank" rel="noopener noreferrer" color="brand.500" _hover={{ color: 'brand.600' }} transition="color 0.2s">
                                            <Icon as={FiExternalLink} boxSize={5} />
                                        </Box>
                                    )}
                                </HStack>
                            </Box>
                        ))}
                    </Flex>

                    {/* Second Scrolling Block (Duplicate) */}
                    <Flex 
                        gap="32px" 
                        className="marquee-content" 
                        aria-hidden="true"
                        animation={prefersReducedMotion ? 'none' : `${scrollAnimation} 40s linear infinite`}
                    >
                        {baseRepeat.map((cert, index) => (
                            <Box
                                key={`second-${cert.id}-${index}`}
                                w={{ base: "300px", md: "400px" }}
                                flexShrink={0}
                                bg={cardBg}
                                p={8}
                                borderRadius="2xl"
                                boxShadow={useColorModeValue('md', 'dark-lg')}
                                border="1px solid"
                                borderColor={cardBorder}
                                transition="all 0.3s cubic-bezier(0.4, 0, 0.2, 1)"
                                _hover={{ transform: 'translateY(-6px)', boxShadow: useColorModeValue('xl', 'dark-lg'), borderColor: hoverBorderColor }}
                                position="relative"
                                display="flex"
                                flexDirection="column"
                            >
                                <Icon as={FiAward} boxSize={10} color={cardIssuer} mb={6} opacity="0.8" />

                                <HStack justify="space-between" align="start" mb={4}>
                                    <VStack align="start" spacing={1}>
                                        <Heading as="h3" size="md" color={cardTitle} lineHeight="tall">
                                            {cert.title}
                                        </Heading>
                                        <Text fontSize="sm" fontWeight="bold" color={cardIssuer} textTransform="uppercase" letterSpacing="wide">
                                            {cert.issuer}
                                        </Text>
                                    </VStack>
                                </HStack>

                                <Text fontSize="md" color={cardDesc} mb={6} flex="1">
                                    {cert.description}
                                </Text>

                                <HStack justify="space-between" mt="auto" pt={4}>
                                    <Text fontSize="sm" fontWeight="semibold" bg={dateBg} color={dateColor} px={3} py={1} borderRadius="md">
                                        Received: {cert.date}
                                    </Text>
                                    {cert.link && cert.link !== "#" && (
                                        <Box as="a" href={cert.link} target="_blank" rel="noopener noreferrer" color="brand.500" _hover={{ color: 'brand.600' }} transition="color 0.2s">
                                            <Icon as={FiExternalLink} boxSize={5} />
                                        </Box>
                                    )}
                                </HStack>
                            </Box>
                        ))}
                    </Flex>
                </Flex>
            </Box>
        </Box>
    );
};

export default CertificationsSection;

import { Box, Flex, Heading, Text, VStack, HStack, Stack, Input, Textarea, Button, FormControl, FormLabel, FormErrorMessage, Icon, useToast, usePrefersReducedMotion, useColorModeValue } from '@chakra-ui/react';
import { motion } from 'framer-motion';
import { useState } from 'react';
import { FaEnvelope, FaMapMarkerAlt, FaPhoneAlt, FaGithub, FaLinkedin, FaTwitter, FaInstagram } from 'react-icons/fa';
import { profile } from '../data/profile';

const MotionBox = motion(Box);
const SocialIcon = ({ icon: IconType, href }) => (
    <Box as="a" href={href} target="_blank" rel="noopener noreferrer" color="whiteAlpha.800" _hover={{ color: 'white', transform: 'scale(1.1)' }} transition="all 0.2s">
        <Icon as={IconType} boxSize={6} />
    </Box>
);

const ContactSection = () => {
    const [formData, setFormData] = useState({ name: '', email: '', subject: '', message: '' });
    const [errors, setErrors] = useState({});
    const [isLoading, setIsLoading] = useState(false);
    const toast = useToast();
    const prefersReducedMotion = usePrefersReducedMotion();

    const bg = useColorModeValue('bg', 'gray.900');
    const titleColor = useColorModeValue('gray.900', 'white');
    const subtitleColor = useColorModeValue('muted', 'gray.400');
    const formBg = useColorModeValue('white', 'gray.800');
    const formBorder = useColorModeValue('gray.100', 'whiteAlpha.200');
    const inputBg = useColorModeValue('gray.50', 'whiteAlpha.50');
    const inputFocusBg = useColorModeValue('white', 'gray.700');
    const labelColor = useColorModeValue('gray.700', 'gray.300');

    const handleValidation = () => {
        let newErrors = {};
        if (!formData.name.trim()) newErrors.name = "Name is required";
        if (!formData.email.trim()) newErrors.email = "Email is required";
        else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) newErrors.email = "Invalid email format";
        if (!formData.subject.trim()) newErrors.subject = "Subject is required";
        if (!formData.message.trim()) newErrors.message = "Message is required";
        return newErrors;
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        const validationErrors = handleValidation();
        if (Object.keys(validationErrors).length > 0) {
            setErrors(validationErrors);
            return;
        }

        setErrors({});
        setIsLoading(true);

        // Send form data to himarbi.dev@gmail.com using FormSubmit
        fetch("https://formsubmit.co/ajax/himarbi.dev@gmail.com", {
            method: "POST",
            headers: {
                'Content-Type': 'application/json',
                'Accept': 'application/json'
            },
            body: JSON.stringify({
                name: formData.name,
                email: formData.email,
                subject: formData.subject,
                message: formData.message
            })
        })
            .then(response => response.json())
            .then(data => {
                setIsLoading(false);
                if (data.success) {
                    setFormData({ name: '', email: '', subject: '', message: '' });
                    toast({
                        title: "Message sent!",
                        description: "Thank you for reaching out. I'll get back to you shortly.",
                        status: "success",
                        duration: 5000,
                        isClosable: true,
                        position: 'bottom-right'
                    });
                } else {
                    throw new Error("Form submission failed");
                }
            })
            .catch(error => {
                setIsLoading(false);
                toast({
                    title: "Error sending message.",
                    description: "Something went wrong. Please try again later.",
                    status: "error",
                    duration: 5000,
                    isClosable: true,
                    position: 'bottom-right'
                });
            });
    };

    return (
        <Box id="contact" py={20} bg={bg}>
            <Box maxW="1280px" mx="auto" px={{ base: 6, md: 8 }}>
                <MotionBox
                    initial={{ opacity: 0, y: prefersReducedMotion ? 0 : 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: '-100px' }}
                    transition={{ duration: 0.5, ease: [0.4, 0, 0.2, 1] }}
                >
                    <Heading as="h2" size="2xl" mb={4} textAlign="center" color={titleColor}>
                        Let's Talk
                    </Heading>
                    <Text fontSize="lg" color={subtitleColor} textAlign="center" maxW="2xl" mx="auto" mb={16}>
                        Got a project in mind or looking for a motivated team member? Feel free to reach out. I'm open to discussing new opportunities.
                    </Text>
                </MotionBox>

                <Flex direction={{ base: 'column', lg: 'row' }} gap={12} bg={formBg} borderRadius="3xl" overflow="hidden" boxShadow={useColorModeValue('xl', 'dark-lg')} border="1px solid" borderColor={formBorder}>

                    {/* Contact Information Side */}
                    <Box flex={1} bg="brand.600" color="white" p={{ base: 6, md: 16 }} position="relative" overflow="hidden">
                        <MotionBox
                            initial={{ opacity: 0, x: prefersReducedMotion ? 0 : -30 }}
                            whileInView={{ opacity: 1, x: 0 }}
                            viewport={{ once: true, margin: '-50px' }}
                            transition={{ duration: 0.5, ease: [0.4, 0, 0.2, 1] }}
                        >
                            <Box position="relative" zIndex={1}>
                                <Heading as="h3" size="lg" mb={6} color="white">
                                    Contact Information
                                </Heading>
                                <Text fontSize="lg" color="whiteAlpha.800" mb={12}>
                                    Fill up the form and I will get back to you shortly.
                                </Text>

                                <VStack align="flex-start" spacing={8} mb={16}>
                                    <HStack spacing={4}>
                                        <Icon as={FaPhoneAlt} boxSize={5} color="brand.200" />
                                        <Text fontSize="lg">+252 61 931 4558</Text>
                                    </HStack>
                                    <HStack spacing={4}>
                                        <Icon as={FaEnvelope} boxSize={5} color="brand.200" />
                                        <Text fontSize="lg">himarbi.dev@gmail.com</Text>
                                    </HStack>
                                    <HStack spacing={4}>
                                        <Icon as={FaMapMarkerAlt} boxSize={5} color="brand.200" />
                                        <Text fontSize="lg">Mogadishu, Somalia</Text>
                                    </HStack>
                                </VStack>

                                <HStack spacing={6}>
                                    <SocialIcon icon={FaGithub} href={profile.socials.github} />
                                    <SocialIcon icon={FaLinkedin} href={profile.socials.linkedin} />
                                    <SocialIcon icon={FaTwitter} href={profile.socials.twitter} />
                                    <SocialIcon icon={FaInstagram} href={profile.socials.instagram} />
                                </HStack>
                            </Box>
                        </MotionBox>

                        {/* Decorative circles */}
                        <Box position="absolute" bottom="-10%" right="-10%" w="250px" h="250px" bg="brand.500" borderRadius="full" opacity="0.5" zIndex={0} />
                        <Box position="absolute" top="10%" right="10%" w="100px" h="100px" bg="brand.400" borderRadius="full" opacity="0.5" zIndex={0} />
                    </Box>

                    {/* Form Side */}
                    <Box flex={1} p={{ base: 8, md: 16 }}>
                        <MotionBox
                            initial={{ opacity: 0, x: prefersReducedMotion ? 0 : 30 }}
                            whileInView={{ opacity: 1, x: 0 }}
                            viewport={{ once: true, margin: '-50px' }}
                            transition={{ duration: 0.5, ease: [0.4, 0, 0.2, 1] }}
                        >
                            <form onSubmit={handleSubmit}>
                                <VStack spacing={6} align="stretch">
                                    <Stack spacing={6} direction={{ base: 'column', md: 'row' }} w="full">
                                        <FormControl isInvalid={errors.name} isRequired>
                                            <FormLabel color={labelColor} fontWeight="bold">Your Name</FormLabel>
                                            <Input
                                                type="text"
                                                placeholder="John Doe"
                                                bg={inputBg}
                                                border="none"
                                                _focus={{ bg: inputFocusBg, boxShadow: "outline" }}
                                                value={formData.name}
                                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                            />
                                            <FormErrorMessage>{errors.name}</FormErrorMessage>
                                        </FormControl>

                                        <FormControl isInvalid={errors.email} isRequired>
                                            <FormLabel color={labelColor} fontWeight="bold">Your Email</FormLabel>
                                            <Input
                                                type="email"
                                                placeholder="john@example.com"
                                                bg={inputBg}
                                                border="none"
                                                _focus={{ bg: inputFocusBg, boxShadow: "outline" }}
                                                value={formData.email}
                                                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                            />
                                            <FormErrorMessage>{errors.email}</FormErrorMessage>
                                        </FormControl>
                                    </Stack>

                                    <FormControl isInvalid={errors.subject} isRequired>
                                        <FormLabel color={labelColor} fontWeight="bold">Subject</FormLabel>
                                        <Input
                                            type="text"
                                            placeholder="Project Inquiry"
                                            bg={inputBg}
                                            border="none"
                                            _focus={{ bg: inputFocusBg, boxShadow: "outline" }}
                                            value={formData.subject}
                                            onChange={(e) => setFormData({ ...formData, subject: e.target.value })}
                                        />
                                        <FormErrorMessage>{errors.subject}</FormErrorMessage>
                                    </FormControl>

                                    <FormControl isInvalid={errors.message} isRequired>
                                        <FormLabel color={labelColor} fontWeight="bold">Message</FormLabel>
                                        <Textarea
                                            placeholder="Tell me about your project..."
                                            rows={6}
                                            bg={inputBg}
                                            border="none"
                                            _focus={{ bg: inputFocusBg, boxShadow: "outline" }}
                                            value={formData.message}
                                            onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                                        />
                                        <FormErrorMessage>{errors.message}</FormErrorMessage>
                                    </FormControl>

                                    <Button
                                        type="submit"
                                        colorScheme="brand"
                                        size="lg"
                                        w="full"
                                        mt={4}
                                        isLoading={isLoading}
                                        loadingText="Sending..."
                                    >
                                        Send Message
                                    </Button>
                                </VStack>
                            </form>
                        </MotionBox>
                    </Box>
                </Flex>
            </Box>
        </Box>
    );
};

export default ContactSection;

import { useState, useEffect } from 'react';
import { Box, usePrefersReducedMotion, useColorModeValue } from '@chakra-ui/react';
import { motion, useSpring } from 'framer-motion';

const MotionBox = motion(Box);

const CursorGlow = () => {
    const prefersReducedMotion = usePrefersReducedMotion();
    const cursorColor = useColorModeValue('rgba(37, 99, 235, 0.1)', 'rgba(96, 165, 250, 0.15)');

    const springConfig = { damping: 25, stiffness: 700 };
    const mouseX = useSpring(0, springConfig);
    const mouseY = useSpring(0, springConfig);

    useEffect(() => {
        if (prefersReducedMotion) return;

        const handleMouseMove = (e) => {
            mouseX.set(e.clientX - 150); // Offset by half the width/height to center
            mouseY.set(e.clientY - 150);
        };

        window.addEventListener('mousemove', handleMouseMove);
        return () => window.removeEventListener('mousemove', handleMouseMove);
    }, [mouseX, mouseY, prefersReducedMotion]);

    if (prefersReducedMotion) return null;

    return (
        <MotionBox
            position="fixed"
            top={0}
            left={0}
            w="300px"
            h="300px"
            bg={`radial-gradient(circle, ${cursorColor} 0%, transparent 70%)`}
            borderRadius="full"
            pointerEvents="none"
            zIndex={9998} // Behind header but above content
            style={{
                x: mouseX,
                y: mouseY,
            }}
        />
    );
};

export default CursorGlow;

import { Box, Heading, Text, VStack, HStack, Circle, Divider, usePrefersReducedMotion, useColorModeValue } from '@chakra-ui/react';
import { motion } from 'framer-motion';
import { experienceList } from '../data/experience';

const MotionBox = motion(Box);
const MotionHStack = motion(HStack);

const ExperienceSection = () => {
    const prefersReducedMotion = usePrefersReducedMotion();

    const bg = useColorModeValue('white', 'gray.900');
    const titleColor = useColorModeValue('gray.900', 'white');
    const subtitleColor = useColorModeValue('muted', 'gray.400');

    const cardBg = useColorModeValue('white', 'gray.800');
    const cardBorder = useColorModeValue('gray.200', 'whiteAlpha.200');
    const cardTitle = useColorModeValue('gray.800', 'white');
    const cardCompany = useColorModeValue('gray.600', 'gray.400');
    const cardText = useColorModeValue('gray.700', 'gray.300');

    const dateBg = useColorModeValue('brand.50', 'whiteAlpha.100');
    const dateColor = useColorModeValue('brand.600', 'brand.300');
